1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import * as THREE from 'three';
3	import type { Element } from '@bim-ai/core';
4	
5	import { useBimStore } from '../state/store';
6	import { useTheme } from '../state/useTheme';
7	import { liveTokenReader } from '../viewport/materials';
8	import { collectWallAnchors, snapPlanPoint } from './snapEngine';
9	import {
10	  buildPlanProjectionQuery,
11	  extractPlanAnnotationHints,
12	  extractPlanCategoryGraphicHintsV0,
13	  extractPlanGraphicHints,
14	  extractPlanPrimitives,
15	  extractPlanTagStyleHints,
16	  extractRoomColorLegend,
17	  extractRoomProgrammeLegendEvidenceV0,
18	  fetchPlanProjectionWire,
19	} from './planProjectionWire';
20	import {
21	  resolvePlanAnnotationHints,
22	  resolvePlanGraphicHints,
23	  resolvePlanTagStyleLane,
24	  resolvePlanViewDisplay,
25	} from './planProjection';
26	import { rebuildPlanMeshes } from './symbology';
27	
28	function readPlanToken(name: string, fallback: string): string {
29	  const v = liveTokenReader().read(name);
30	  return v && v.trim().length > 0 ? v : fallback;
31	}
32	
33	const SLICE_Y = 0.02;
34	
35	function orthoExtents(halfWorldM: number) {
36	  const stepMm = halfWorldM < 5 ? 250 : halfWorldM < 12 ? 500 : halfWorldM < 24 ? 1000 : 2000;
37	  const snapMm = Math.max(stepMm * 3, 300);
38	  return { stepMm, snapMm };
39	}
40	
41	function rayToPlanMm(
42	  renderer: THREE.WebGLRenderer,
43	  camera: THREE.Camera,
44	  clientX: number,
45	  clientY: number,
46	) {
47	  const rect = renderer.domElement.getBoundingClientRect();
48	  const ndc = new THREE.Vector2(
49	    ((clientX - rect.left) / rect.width) * 2 - 1,
50	    -(((clientY - rect.top) / rect.height) * 2 - 1),
51	  );
52	  const raycaster = new THREE.Raycaster();
53	  raycaster.setFromCamera(ndc, camera);
54	  const plane = new THREE.Plane(new THREE.Vector3(0, 1, 0), -SLICE_Y);
55	  const pt = new THREE.Vector3();
56	  if (!raycaster.ray.intersectPlane(plane, pt)) return null;
57	  return { xMm: pt.x * 1000, yMm: pt.z * 1000 };
58	}
59	
60	type Draft =
61	  | { kind: 'wall'; sx: number; sy: number }
62	  | { kind: 'room'; verts: Array<{ xMm: number; yMm: number }> }
63	  | { kind: 'grid'; sx: number; sy: number }
64	  | { kind: 'dim'; ax: number; ay: number }
65	  | { kind: 'room_rect'; sx: number; sy: number };
66	
67	function nearestWallAt(
68	  elementsById: Record<string, Element>,
69	  activeLevelId: string | undefined,
70	  xMm: number,
71	  yMm: number,
72	): { wall: Extract<Element, { kind: 'wall' }>; alongT: number; distMm: number } | undefined {
73	  const px = xMm / 1000;
74	  const pz = yMm / 1000;
75	  let best:
76	    | { wall: Extract<Element, { kind: 'wall' }>; alongT: number; distMm: number }
77	    | undefined;
78	  for (const el of Object.values(elementsById)) {
79	    if (el.kind !== 'wall') continue;
80	    if (activeLevelId && el.levelId !== activeLevelId) continue;
81	    const ax = el.start.xMm / 1000;
82	    const az = el.start.yMm / 1000;
83	    const bx = el.end.xMm / 1000;
84	    const bz = el.end.yMm / 1000;
85	    const abx = bx - ax;
86	    const abz = bz - az;
87	    const len2 = abx * abx + abz * abz;
88	    const rawT = Math.max(
89	      0,
90	      Math.min(1, ((px - ax) * abx + (pz - az) * abz) / Math.max(len2, 1e-9)),
91	    );
92	    const fx = ax + abx * rawT;
93	    const fz = az + abz * rawT;
94	    const distMm = Math.hypot((px - fx) * 1000, (pz - fz) * 1000);
95	    if (!best || distMm < best.distMm) best = { wall: el, alongT: rawT, distMm };
96	  }
97	  return best;
98	}
99	
100	function guessGridLabel(sxMm: number, syMm: number, exMm: number, eyMm: number) {
101	  const horizontal = Math.abs(eyMm - syMm) < Math.abs(exMm - sxMm);
102	  return horizontal
103	    ? `Axis ${Math.floor(Math.abs((syMm + 5000) / 3800)) + 1}`
104	    : String.fromCharCode(66 + Math.min(10, Math.floor(Math.abs(exMm - sxMm + 8200) / 4200)));
105	}
106	
107	type Props = {
108	  wsConnected: boolean;
109	  activeLevelResolvedId: string;
110	  onSemanticCommand: (cmd: Record<string, unknown>) => void;
111	};
112	
113	export function PlanCanvas({ wsConnected, activeLevelResolvedId, onSemanticCommand }: Props) {
114	  void wsConnected;
115	  const theme = useTheme();
116	  const mountRef = useRef<HTMLDivElement | null>(null);
117	  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
118	  const sceneRef = useRef<THREE.Scene | null>(null);
119	  const cameraRef = useRef<THREE.OrthographicCamera | null>(null);
120	  const rootRef = useRef<THREE.Group | null>(null);
121	  const previewRef = useRef<THREE.Line | null>(null);
122	  const dragRef = useRef({ dragging: false, lastXmm: 0, lastZmm: 0, camX: 0, camZ: 0 });
123	  const skipClickRef = useRef(false);
124	  const camRef = useRef({ camX: 0, camZ: -2.8, half: 22 });
125	  const draftRef = useRef<Draft | undefined>(undefined);
126	  const [hudMm, setHudMm] = useState<{ xMm: number; yMm: number }>();
127	  const [halfUi, setHalfUi] = useState(22);
128	  const [geomEpoch, bumpGeom] = useState(0);
129	  const [roomColorLegend, setRoomColorLegend] = useState<
130	    Array<{
131	      label: string;
132	      schemeColorHex: string;
133	      programmeCode?: string;
134	      department?: string;
135	      functionLabel?: string;
136	    }>
137	  >([]);
138	  const [wireGraphicHints, setWireGraphicHints] = useState<ReturnType<
139	    typeof extractPlanGraphicHints
140	  > | null>(null);
141	  const [wireAnnotationHints, setWireAnnotationHints] = useState<ReturnType<
142	    typeof extractPlanAnnotationHints
143	  > | null>(null);
144	  const [wireTagStyleHints, setWireTagStyleHints] = useState<ReturnType<
145	    typeof extractPlanTagStyleHints
146	  > | null>(null);
147	
148	  const elementsById = useBimStore((s) => s.elementsById);
149	  const selectedId = useBimStore((s) => s.selectedId);
150	  const modelId = useBimStore((s) => s.modelId);
151	  const revision = useBimStore((s) => s.revision);
152	  const planProjectionPrimitives = useBimStore((s) => s.planProjectionPrimitives);
153	  const setPlanProjectionPrimitives = useBimStore((s) => s.setPlanProjectionPrimitives);
154	  const setPlanRoomSchemeWireReadout = useBimStore((s) => s.setPlanRoomSchemeWireReadout);
155	  const activePlanViewId = useBimStore((s) => s.activePlanViewId);
156	  const planPresentation = useBimStore((s) => s.planPresentationPreset);
157	  const planTool = useBimStore((s) => s.planTool);
158	  const orthoSnapHold = useBimStore((s) => s.orthoSnapHold);
159	  const selectEl = useBimStore((s) => s.select);
160	
161	  const display = useMemo(
162	    () =>
163	      resolvePlanViewDisplay(
164	        elementsById,
165	        activePlanViewId,
166	        activeLevelResolvedId || undefined,
167	        planPresentation,
168	      ),
169	    [elementsById, activePlanViewId, activeLevelResolvedId, planPresentation],
170	  );
171	
172	  const mergedGraphicHints = useMemo(() => {
173	    if (wireGraphicHints) return wireGraphicHints;
174	    return resolvePlanGraphicHints(elementsById, activePlanViewId);
175	  }, [wireGraphicHints, elementsById, activePlanViewId]);
176	
177	  const mergedAnnotationHints = useMemo(() => {
178	    if (wireAnnotationHints !== null) return wireAnnotationHints;
179	    return resolvePlanAnnotationHints(elementsById, activePlanViewId);
180	  }, [wireAnnotationHints, elementsById, activePlanViewId]);
181	
182	  const planTagFontScales = useMemo(() => {
183	    const pvId = display.planViewElementId;
184	    const ro = resolvePlanTagStyleLane(elementsById, pvId, 'opening');
185	    const rr = resolvePlanTagStyleLane(elementsById, pvId, 'room');
186	    const bo = wireTagStyleHints?.opening?.textSizePt;
187	    const br = wireTagStyleHints?.room?.textSizePt;
188	    const openingPt = typeof bo === 'number' && Number.isFinite(bo) ? bo : ro.textSizePt;
189	    const roomPt = typeof br === 'number' && Number.isFinite(br) ? br : rr.textSizePt;
190	    return { opening: openingPt / 10, room: roomPt / 10 };
191	  }, [wireTagStyleHints, elementsById, display.planViewElementId]);
192	
193	  const hiddenKey = useMemo(
194	    () => [...display.hiddenSemanticKinds].sort().join('|'),
195	    [display.hiddenSemanticKinds],
196	  );
