409	    );
410	    const sections = (Object.values(elementsById) as Element[]).filter(
411	      (e): e is Extract<Element, { kind: 'section_cut' }> => e.kind === 'section_cut',
412	    );
413	    const sheets = (Object.values(elementsById) as Element[]).filter(
414	      (e): e is Extract<Element, { kind: 'sheet' }> => e.kind === 'sheet',
415	    );
416	    const schedules = (Object.values(elementsById) as Element[]).filter(
417	      (e): e is Extract<Element, { kind: 'schedule' }> => e.kind === 'schedule',
418	    );
419	    return [
420	      {
421	        id: 'project',
422	        label: 'Project',
423	        rows: [
424	          {
425	            id: 'levels',
426	            label: 'Levels',
427	            children: levels.map((l) => ({ id: l.id, label: l.name, hint: `${l.elevationMm}mm` })),
428	          },
429	        ],
430	      },
431	      {
432	        id: 'views',
433	        label: 'Views',
434	        rows: [
435	          {
436	            id: 'plans',
437	            label: 'Floor Plans',
438	            children: planViews.map((p) => ({ id: p.id, label: p.name })),
439	          },
440	          {
441	            id: 'viewpoints',
