474	  }, [elementsById, selectedId]);
475	
476	  /* ── Status bar wiring ────────────────────────────────────────────── */
477	  const levels = useMemo(() => {
478	    return (Object.values(elementsById) as Element[])
479	      .filter((e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level')
480	      .sort((a, b) => a.elevationMm - b.elevationMm)
481	      .map((l) => ({ id: l.id, label: l.name }));
482	  }, [elementsById]);
483	  const activeLevel = levels.find((l) => l.id === activeLevelId) ??
484	    levels[0] ?? { id: '', label: '—' };
