509	
510	  /* ── Command palette candidates (§18) ─────────────────────────────── */
511	  const paletteCandidates = useMemo<CommandCandidate[]>(() => {
512	    const items: CommandCandidate[] = [];
513	    // Tool sources
514	    for (const tool of Object.values(TOOL_REGISTRY)) {
515	      items.push({
516	        id: `tool.${tool.id}`,
