647	            </div>
648	            <TabBar
649	              tabs={tabsState.tabs}
650	              activeId={tabsState.activeId}
651	              onActivate={(id) => {
652	                handleTabActivate(id);
653	                const t = tabsState.tabs.find((x) => x.id === id);
654	                if (t) {
655	                  if (t.kind === 'plan' || t.kind === 'plan-3d') setViewerMode('plan_canvas');
656	                  else if (t.kind === '3d') setViewerMode('orbit_3d');
657	                  setMode(t.kind as WorkspaceMode);
658	                }
659	              }}
660	              onClose={handleTabClose}
661	              onReorder={(from, to) => setTabsState((s) => reorderTab(s, from, to))}
662	              onAdd={(kind) => {
663	                const fallback = defaultTabFallbackForKind(kind, elementsById, activeLevelId);
664	                if (!fallback) return;
665	                setTabsState((s) => activateOrOpenKind(s, kind, fallback));
666	                setMode(kind as WorkspaceMode);
667	                if (kind === 'plan' || kind === 'plan-3d') setViewerMode('plan_canvas');
668	                else if (kind === '3d') setViewerMode('orbit_3d');
669	              }}
670	            />
671	          </div>
672	        }
673	        leftRail={
674	          <LeftRail
675	            sections={browserSections}
676	            activeRowId={activeLevelId}
677	            onRowActivate={(id) => {
678	              const el = elementsById[id];
679	              if (!el) {
680	                // Levels nest under "project" → "levels"; check the nested children.
681	                const isLevel = browserSections
682	                  .find((s) => s.id === 'project')
683	                  ?.rows.find((r) => r.id === 'levels')
684	                  ?.children?.some((c) => c.id === id);
685	                if (isLevel) setActiveLevelId(id);
686	                return;
687	              }
688	              if (el.kind === 'level') {
689	                setActiveLevelId(id);
690	                openTabFromElement(el);
691	                handleModeChange('plan');
692	                return;
693	              }
694	              if (el.kind === 'plan_view') {
695	                openTabFromElement(el);
696	                handleModeChange('plan');
697	                select(id);
698	                return;
699	              }
700	              if (el.kind === 'viewpoint') {
701	                openTabFromElement(el);
702	                handleModeChange('3d');
703	                select(id);
704	                return;
705	              }
706	              if (el.kind === 'section_cut') {
707	                openTabFromElement(el);
708	                handleModeChange('section');
709	                select(id);
710	                return;
711	              }
712	              if (el.kind === 'sheet') {
713	                openTabFromElement(el);
714	                handleModeChange('sheet');
715	                select(id);
716	                return;
717	              }
718	              if (el.kind === 'schedule') {
719	                openTabFromElement(el);
720	                handleModeChange('schedule');
721	                select(id);
722	                return;
723	              }
724	              select(id);
725	            }}
726	          />
727	        }
728	        leftRailCollapsed={<LeftRailCollapsed sections={browserSections} />}
729	        canvas={
730	          <div style={canvasContainerStyle} data-testid="redesign-canvas-root">
731	            {showEmptyState ? (
732	              <EmptyStateOverlay
733	                headline={emptyHint.headline}
734	                hint={emptyHint.hint}
735	                ctaLabel={emptyHint.cta?.label ?? null}
736	                ctaPending={seedLoading}
737	                ctaError={seedError}
738	                onCta={() => void insertSeedHouse()}
739	              />
740	            ) : null}
741	            <FloatingPalette
742	              mode={mode}
743	              activeTool={legacyToToolId(planTool)}
744	              onToolSelect={handleToolSelect}
745	              disabledContext={toolDisabledContext}
746	            />
747	            <CanvasMount
748	              mode={(activeTab?.kind as WorkspaceMode | undefined) ?? mode}
749	              viewerMode={viewerMode}
750	              activeLevelId={
751	                activeTab?.kind === 'plan' || activeTab?.kind === 'plan-3d'
752	                  ? activeTab.targetId ?? activeLevelId ?? ''
753	                  : activeLevelId ?? ''
754	              }
755	              elementsById={elementsById}
756	              onSemanticCommand={(cmd) => void onSemanticCommand(cmd)}
757	            />
758	          </div>
759	        }
760	        rightRail={(() => {
761	          const el = selectedId ? elementsById[selectedId] : undefined;
762	          return (
763	            <Inspector
764	              selection={inspectorSelection}
765	              tabs={{
766	                properties: el ? (
767	                  InspectorPropertiesFor(el)
768	                ) : (
769	                  <InspectorEmptyTab message="No element selected." />
770	                ),
771	                constraints: el ? (
772	                  InspectorConstraintsFor(el)
773	                ) : (
774	                  <InspectorEmptyTab message="No element selected." />
775	                ),
776	                identity: el ? (
777	                  InspectorIdentityFor(el)
778	                ) : (
779	                  <InspectorEmptyTab message="No element selected." />
780	                ),
781	              }}
782	              emptyStateActions={[
783	                {
784	                  hotkey: 'W',
785	                  label: 'Draw a wall',
786	                  onTrigger: () => {
787	                    if (mode !== 'plan' && mode !== 'plan-3d') handleModeChange('plan');
788	                    setPlanTool('wall');
789	                  },
790	                },
791	                {
792	                  hotkey: 'D',
793	                  label: 'Insert a door',
794	                  onTrigger: () => {
795	                    if (mode !== 'plan' && mode !== 'plan-3d') handleModeChange('plan');
796	                    setPlanTool('door');
797	                  },
798	                },
799	                {
800	                  hotkey: 'M',
801	                  label: 'Drop a room marker',
802	                  onTrigger: () => {
803	                    if (mode !== 'plan' && mode !== 'plan-3d') handleModeChange('plan');
804	                    setPlanTool('room');
805	                  },
806	                },
807	              ]}
808	              onClearSelection={() => select(undefined)}
809	            />
810	          );
811	        })()}
812	        statusBar={
813	          <StatusBar
814	            level={activeLevel}
815	            levels={levels}
816	            onLevelChange={setActiveLevelId}
817	            toolLabel={TOOL_REGISTRY[legacyToToolId(planTool)]?.label ?? null}
818	            gridOn={true}
819	            cursorMm={cursorMm}
820	            undoDepth={0}
821	            wsState="connected"
822	            saveState="saved"
823	          />
824	        }
825	      />
826	    </>
827	  );
828	}
829	
830	const canvasContainerStyle: CSSProperties = {
831	  position: 'relative',
832	  width: '100%',
833	  height: '100%',
834	};
835	
836	function FloatingPalette({
837	  mode,
838	  activeTool,
839	  onToolSelect,
840	  disabledContext,
841	}: {
842	  mode: WorkspaceMode;
843	  activeTool: ToolId;
844	  onToolSelect: (id: ToolId) => void;
845	  disabledContext: ToolDisabledContext;
846	}): JSX.Element | null {
847	  if (mode === 'sheet' || mode === 'schedule' || mode === 'agent') return null;
848	  return (
849	    <div
850	      style={{
851	        position: 'absolute',
852	        top: 12,
853	        left: '50%',
