865	  );
866	}
867	
868	function CanvasMount({
869	  mode,
870	  viewerMode,
871	  activeLevelId,
872	  elementsById,
873	  onSemanticCommand,
874	}: {
875	  mode: WorkspaceMode;
876	  viewerMode: 'plan_canvas' | 'orbit_3d';
877	  activeLevelId: string;
878	  elementsById: Record<string, Element>;
879	  onSemanticCommand: (cmd: Record<string, unknown>) => void;
880	}): JSX.Element {
881	  if (mode === 'plan-3d') {
882	    return (
883	      <div
884	        style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', height: '100%', width: '100%' }}
885	      >
886	        <div style={{ position: 'relative', borderRight: '1px solid var(--color-border)' }}>
887	          <PlanCanvas
888	            wsConnected={false}
889	            activeLevelResolvedId={activeLevelId ?? ''}
890	            onSemanticCommand={onSemanticCommand}
891	          />
892	        </div>
893	        <div style={{ position: 'relative' }}>
894	          <Viewport wsConnected={false} />
895	        </div>
896	      </div>
897	    );
898	  }
899	  if (mode === '3d') return <Viewport wsConnected={false} />;
900	  if (mode === 'plan')
901	    return (
902	      <PlanCanvas
903	        wsConnected={false}
904	        activeLevelResolvedId={activeLevelId}
905	        onSemanticCommand={onSemanticCommand}
906	      />
907	    );
908	  if (mode === 'section') return <SectionModeShell elementsById={elementsById} />;
909	  if (mode === 'sheet') return <SheetModeShell elementsById={elementsById} />;
910	  if (mode === 'schedule') return <ScheduleModeShell elementsById={elementsById} />;
911	  if (mode === 'agent') return <AgentReviewModeShell />;
912	  return viewerMode === 'orbit_3d' ? (
913	    <Viewport wsConnected={false} />
914	  ) : (
915	    <PlanCanvas
916	      wsConnected={false}
917	      activeLevelResolvedId={activeLevelId}
918	      onSemanticCommand={onSemanticCommand}
919	    />
920	  );
921	}
922	
923	function EmptyStateOverlay({
924	  headline,
925	  hint,
926	  ctaLabel,
927	  ctaPending,
928	  ctaError,
929	  onCta,
930	}: {
931	  headline: string;
932	  hint: string;
933	  ctaLabel: string | null;
934	  ctaPending: boolean;
935	  ctaError: string | null;
936	  onCta: () => void;
937	}): JSX.Element {
938	  return (
939	    <div
940	      role="status"
941	      aria-live="polite"
942	      style={{
943	        position: 'absolute',
944	        inset: 0,
945	        zIndex: 5,
946	        display: 'flex',
947	        alignItems: 'center',
948	        justifyContent: 'center',
949	        pointerEvents: 'none',
950	      }}
951	    >
952	      <div className="pointer-events-auto flex flex-col items-center gap-3 rounded-lg bg-surface/95 px-6 py-5 text-center shadow-elev-2 backdrop-blur">
953	        <div className="text-md font-medium text-foreground">{headline}</div>
954	        <div className="text-sm text-muted">{hint}</div>
955	        {ctaLabel ? (
956	          <button
957	            type="button"
958	            onClick={onCta}
959	            disabled={ctaPending}
960	            data-testid="canvas-empty-cta"
961	            className="rounded-md bg-accent px-4 py-1.5 text-sm font-medium text-accent-foreground shadow-elev-1 hover:bg-accent/90 disabled:cursor-not-allowed disabled:opacity-60"
962	          >
963	            {ctaPending ? 'Loading…' : ctaLabel}
964	          </button>
965	        ) : null}
966	        {ctaError ? (
967	          <div className="text-xs text-danger" data-testid="canvas-empty-error">
968	            {ctaError}
969	          </div>
970	        ) : null}
971	      </div>
972	    </div>
973	  );
974	}
975	
976	function InspectorEmptyTab({ message }: { message: string }): JSX.Element {
977	  return <p className="text-sm text-muted">{message}</p>;
978	}
979	
980	function humanKindLabel(kind: string): string {
981	  return kind.replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
982	}
983	
984	/** Default tab descriptor when a mode pill (or tab `+`) is clicked
985	 * with no specific element. Picks the active level for plan/plan-3d,
986	 * the first viewpoint for 3d, the first section for section, etc. */
987	function defaultTabFallbackForKind(
988	  kind: WorkspaceMode | TabKind,
989	  elementsById: Record<string, Element>,
990	  activeLevelId: string | undefined,
991	): { targetId?: string; label: string } | null {
992	  const all = Object.values(elementsById) as Element[];
993	  if (kind === 'plan' || kind === 'plan-3d') {
994	    const levels = all
995	      .filter((e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level')
996	      .sort((a, b) => a.elevationMm - b.elevationMm);
997	    const lvl = levels.find((l) => l.id === activeLevelId) ?? levels[0];
998	    if (!lvl) return { label: kind === 'plan' ? 'Plan' : 'Plan + 3D' };
999	    return {
1000	      targetId: lvl.id,
1001	      label: kind === 'plan' ? `Plan · ${lvl.name}` : `Plan + 3D · ${lvl.name}`,
1002	    };
1003	  }
1004	  if (kind === '3d') {
1005	    const vp = all.find(
1006	      (e): e is Extract<Element, { kind: 'viewpoint' }> => e.kind === 'viewpoint',
1007	    );
1008	    if (vp) return { targetId: vp.id, label: `3D · ${vp.name}` };
1009	    return { label: '3D · Default' };
1010	  }
1011	  if (kind === 'section') {
1012	    const sec = all.find(
1013	      (e): e is Extract<Element, { kind: 'section_cut' }> => e.kind === 'section_cut',
1014	    );
1015	    if (sec) return { targetId: sec.id, label: `Section · ${sec.name}` };
1016	    return { label: 'Section' };
1017	  }
1018	  if (kind === 'sheet') {
1019	    const sht = all.find((e): e is Extract<Element, { kind: 'sheet' }> => e.kind === 'sheet');
1020	    if (sht) return { targetId: sht.id, label: `Sheet · ${sht.name}` };
1021	    return { label: 'Sheet' };
1022	  }
1023	  if (kind === 'schedule') {
1024	    const s = all.find((e): e is Extract<Element, { kind: 'schedule' }> => e.kind === 'schedule');
1025	    if (s) return { targetId: s.id, label: `Schedule · ${s.name}` };
1026	    return { label: 'Schedule' };
1027	  }
1028	  if (kind === 'agent') {
1029	    return { label: 'Agent review' };
1030	  }
1031	  return null;
1032	}
1033	
1034	/** Suppress an unused-import warning in case the keyboard bindings change. */
1035	export type { KeyboardEvent };
